using Ledgerly.Application.Abstractions; using Ledgerly.Application.Invoices; using Ledgerly.Application.Journals; using Ledgerly.Domain.Entities; using Ledgerly.Domain.Enums; using Ledgerly.Domain.ValueObjects; namespace Ledgerly.Application.Tests; public class InvoiceServiceTests { static readonly Guid Org=Guid.NewGuid(); [Fact] public async Task SendAsync_posts_journal(){ var a=new InMemoryAccountRepository(); var j=new InMemoryJournalRepository(); var c=new InMemoryContactRepository(); var t=new InMemoryTaxCodeRepository(); var i=new InMemoryInvoiceRepository(); var svc=new InvoiceService(i,c,a,t,new JournalService(j,a)); var cust=new Contact(Org,ContactType.Customer,"Acme",null,null,null,null,new CurrencyCode("USD"),PaymentTerms.Net30,null,null); await c.AddAsync(cust); var inc=new Account(Org,"4000","Rev",AccountType.Income,new CurrencyCode("USD"),new Money(0m,new CurrencyCode("USD")),null); var ar=new Account(Org,"1200","AR",AccountType.Asset,new CurrencyCode("USD"),new Money(0m,new CurrencyCode("USD")),null); await a.AddAsync(inc); await a.AddAsync(ar); var inv=await svc.CreateAsync(new CreateInvoiceRequest(Org,cust.Id,"INV-1",new DateOnly(2026,3,1),new DateOnly(2026,3,31),"USD",inc.Id,ar.Id)); await svc.AddLineAsync(Org,inv.Value!.Id,new AddInvoiceLineRequest("Svc",1m,200m,null,0m)); var sent=await svc.SendAsync(Org,inv.Value.Id); Assert.True(sent.IsSuccess); Assert.Equal(InvoiceStatus.Sent,sent.Value!.Status);} sealed class InMemoryInvoiceRepository:IInvoiceRepository{List<Invoice> _l=new(); public Task<Invoice?> GetByIdAsync(Guid o,Guid id,CancellationToken ct=default)=>Task.FromResult(_l.FirstOrDefault(x=>x.OrganizationId==o&&x.Id==id)); public Task<IReadOnlyList<Invoice>> ListByOrganizationAsync(Guid o,CancellationToken ct=default)=>Task.FromResult<IReadOnlyList<Invoice>>(_l.Where(x=>x.OrganizationId==o).ToList()); public Task AddAsync(Invoice inv,CancellationToken ct=default){_l.Add(inv);return Task.CompletedTask;} public Task UpdateAsync(Invoice inv,CancellationToken ct=default)=>Task.CompletedTask;} sealed class InMemoryTaxCodeRepository:ITaxCodeRepository{List<TaxCode> _l=new(); public Task<TaxCode?> GetByIdAsync(Guid o,Guid id,CancellationToken ct=default)=>Task.FromResult(_l.FirstOrDefault(x=>x.OrganizationId==o&&x.Id==id)); public Task<TaxCode?> GetByCodeAsync(Guid o,string code,CancellationToken ct=default)=>Task.FromResult(_l.FirstOrDefault(x=>x.OrganizationId==o&&x.Code==code)); public Task<IReadOnlyList<TaxCode>> ListByOrganizationAsync(Guid o,bool ia=false,CancellationToken ct=default)=>Task.FromResult<IReadOnlyList<TaxCode>>(_l.Where(x=>x.OrganizationId==o&&(!ia?!x.IsArchived:true)).OrderBy(x=>x.Code).ToList()); public Task AddAsync(TaxCode t,CancellationToken ct=default){_l.Add(t);return Task.CompletedTask;} public Task UpdateAsync(TaxCode t,CancellationToken ct=default)=>Task.CompletedTask;} sealed class InMemoryContactRepository:IContactRepository{List<Contact> _l=new(); public Task<Contact?> GetByIdAsync(Guid o,Guid id,CancellationToken ct=default)=>Task.FromResult(_l.FirstOrDefault(x=>x.OrganizationId==o&&x.Id==id)); public Task<IReadOnlyList<Contact>> ListByTypeAsync(Guid o,ContactType t,bool ia=false,CancellationToken ct=default)=>Task.FromResult<IReadOnlyList<Contact>>(_l.Where(x=>x.OrganizationId==o&&x.ContactType==t).ToList()); public Task AddAsync(Contact c,CancellationToken ct=default){_l.Add(c);return Task.CompletedTask;} public Task UpdateAsync(Contact c,CancellationToken ct=default)=>Task.CompletedTask;} sealed class InMemoryJournalRepository:IJournalRepository{List<JournalEntry> _l=new(); public Task<JournalEntry?> GetByIdAsync(Guid o,Guid id,CancellationToken ct=default)=>Task.FromResult(_l.FirstOrDefault(x=>x.OrganizationId==o&&x.Id==id)); public Task<IReadOnlyList<JournalEntry>> ListByOrganizationAsync(Guid o,CancellationToken ct=default)=>Task.FromResult<IReadOnlyList<JournalEntry>>(_l.Where(x=>x.OrganizationId==o).ToList()); public Task<IReadOnlyList<(JournalEntry Entry, JournalLine Line)>> ListPostedLinesByAccountAsync(Guid o,Guid a,DateOnly s,DateOnly e,CancellationToken ct=default)=>Task.FromResult<IReadOnlyList<(JournalEntry Entry, JournalLine Line)>>(_l.Where(x=>x.OrganizationId==o&&x.Status==JournalEntryStatus.Posted&&x.EntryDate>=s&&x.EntryDate<=e).SelectMany(x=>x.Lines.Where(l=>l.AccountId==a).Select(l=>(x,l))).ToList()); public Task<IReadOnlyList<(JournalEntry Entry, JournalLine Line)>> ListPostedLinesAsync(Guid o,DateOnly? s,DateOnly e,CancellationToken ct=default){var q=_l.Where(x=>x.OrganizationId==o&&x.Status==JournalEntryStatus.Posted&&x.EntryDate<=e);if(s.HasValue)q=q.Where(x=>x.EntryDate>=s.Value);return Task.FromResult<IReadOnlyList<(JournalEntry Entry, JournalLine Line)>>(q.SelectMany(x=>x.Lines.Select(l=>(x,l))).ToList());} public Task AddAsync(JournalEntry e,CancellationToken ct=default){_l.Add(e);return Task.CompletedTask;} public Task UpdateAsync(JournalEntry e,CancellationToken ct=default)=>Task.CompletedTask;} sealed class InMemoryAccountRepository:IAccountRepository{List<Account> _l=new(); public Task<Account?> GetByIdAsync(Guid o,Guid id,CancellationToken ct=default)=>Task.FromResult(_l.FirstOrDefault(x=>x.OrganizationId==o&&x.Id==id)); public Task<Account?> GetByCodeAsync(Guid o,string code,CancellationToken ct=default)=>Task.FromResult(_l.FirstOrDefault(x=>x.OrganizationId==o&&x.Code==code)); public Task<IReadOnlyList<Account>> ListByOrganizationAsync(Guid o,bool ia=false,CancellationToken ct=default)=>Task.FromResult<IReadOnlyList<Account>>(_l.Where(x=>x.OrganizationId==o).ToList()); public Task<IReadOnlyList<Account>> GetChildrenAsync(Guid o,Guid p,CancellationToken ct=default)=>Task.FromResult<IReadOnlyList<Account>>(Array.Empty<Account>()); public Task<bool> HasActiveChildrenAsync(Guid o,Guid id,CancellationToken ct=default)=>Task.FromResult(false); public Task AddAsync(Account a,CancellationToken ct=default){_l.Add(a);return Task.CompletedTask;} public Task UpdateAsync(Account a,CancellationToken ct=default)=>Task.CompletedTask;} }
